      "title.univ": `The Universe`,
      "univ.h1": `ALL YOU NEED TO KNOW`,
      "univ.card1": `THE ORIGIN OF THE UNIVERSE`,
      "univ.card2": `SHAPE OF THE UNIVERSE`,
